import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { senderAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Plus, Phone, RefreshCw, Trash2, CheckCircle, Clock, XCircle, X, Info, ShieldCheck } from 'lucide-react';

const inp = {
  width: '100%', padding: '10px 12px', border: '1px solid #e2e8f0',
  borderRadius: '8px', fontSize: '14px', outline: 'none',
  boxSizing: 'border-box', background: 'white', color: '#0f172a',
};

const STATUS = {
  approved  : { bg: '#dcfce7', color: '#166534', icon: CheckCircle,  label: 'Approved'  },
  pending   : { bg: '#fef3c7', color: '#92400e', icon: Clock,        label: 'Pending'   },
  rejected  : { bg: '#fee2e2', color: '#991b1b', icon: XCircle,      label: 'Rejected'  },
  suspended : { bg: '#f3e8ff', color: '#6b21a8', icon: XCircle,      label: 'Suspended' },
};

const StatusBadge = ({ status }) => {
  const s = STATUS[status] || STATUS.pending;
  const Icon = s.icon;
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: '5px',
      padding: '3px 10px', borderRadius: '20px',
      background: s.bg, color: s.color, fontSize: '12px', fontWeight: 600,
    }}>
      <Icon size={12} />{s.label}
    </span>
  );
};

export default function SendersPage() {
  const qc = useQueryClient();
  const { isAdmin } = useAuth();
  const [showModal, setShowModal]   = useState(false);
  const [showInfo, setShowInfo]     = useState(false);
  const [syncResults, setSyncResults] = useState(null);
  const [form, setForm] = useState({
    phone_number   : '',
    friendly_name  : '',
    brand_name     : '',
    campaign_id_10dlc: '',
    brand_id_10dlc   : '',
  });

  const { data: senders = [], isLoading } = useQuery({
    queryKey: ['senders'],
    queryFn : () => senderAPI.getAll().then(r => r.data.data),
  });

  const addMutation = useMutation({
    mutationFn : (data) => senderAPI.add(data),
    onSuccess  : () => { qc.invalidateQueries(['senders']); setShowModal(false); resetForm(); toast.success('Sender number added!'); },
    onError    : (e) => toast.error(e.response?.data?.message || 'Failed to add'),
  });

  const statusMutation = useMutation({
    mutationFn : ({ id, status }) => senderAPI.updateStatus(id, status),
    onSuccess  : () => { qc.invalidateQueries(['senders']); toast.success('Status updated'); },
  });

  const deleteMutation = useMutation({
    mutationFn : (id) => senderAPI.delete(id),
    onSuccess  : () => { qc.invalidateQueries(['senders']); toast.success('Sender removed'); },
  });

  const syncMutation = useMutation({
    mutationFn : () => senderAPI.syncTwilio(),
    onSuccess  : (res) => { setSyncResults(res.data.data); toast.success(`Found ${res.data.data.length} numbers on Twilio`); },
    onError    : (e) => toast.error(e.response?.data?.message || 'Sync failed'),
  });

  const resetForm = () => setForm({ phone_number: '', friendly_name: '', brand_name: '', campaign_id_10dlc: '', brand_id_10dlc: '' });

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.phone_number.startsWith('+')) {
      return toast.error('Phone number must start with + (e.g. +12125551234)');
    }
    addMutation.mutate(form);
  };

  return (
    <div style={{ padding: '32px', background: '#f8fafc', minHeight: '100vh' }}>

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '28px' }}>
        <div>
          <h1 style={{ fontSize: '24px', fontWeight: 700, color: '#0f172a' }}>Sender Numbers</h1>
          <p style={{ color: '#64748b', marginTop: '4px' }}>Manage 10DLC-registered numbers for sending SMS campaigns</p>
        </div>
        <div style={{ display: 'flex', gap: '10px' }}>
          <button onClick={() => setShowInfo(true)} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '9px 16px',
            background: 'white', border: '1px solid #e2e8f0', borderRadius: '8px',
            cursor: 'pointer', fontSize: '13px', fontWeight: 500, color: '#374151',
          }}>
            <Info size={14} /> 10DLC Guide
          </button>
          {isAdmin && (
            <button onClick={() => syncMutation.mutate()} disabled={syncMutation.isPending} style={{
              display: 'flex', alignItems: 'center', gap: '6px', padding: '9px 16px',
              background: 'white', border: '1px solid #e2e8f0', borderRadius: '8px',
              cursor: 'pointer', fontSize: '13px', fontWeight: 500, color: '#374151',
            }}>
              <RefreshCw size={14} className={syncMutation.isPending ? 'animate-spin' : ''} />
              {syncMutation.isPending ? 'Syncing...' : 'Sync Twilio'}
            </button>
          )}
          <button onClick={() => setShowModal(true)} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 20px',
            background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
            border: 'none', borderRadius: '10px', color: 'white',
            fontWeight: 600, fontSize: '14px', cursor: 'pointer',
          }}>
            <Plus size={16} /> Add Number
          </button>
        </div>
      </div>

      {/* Twilio sync results */}
      {syncResults && (
        <div style={{
          background: 'white', borderRadius: '12px', border: '1px solid #e2e8f0',
          padding: '16px', marginBottom: '20px',
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
            <h3 style={{ fontSize: '14px', fontWeight: 600, color: '#0f172a' }}>
              Numbers found on your Twilio account ({syncResults.length})
            </h3>
            <button onClick={() => setSyncResults(null)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}>
              <X size={16} />
            </button>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            {syncResults.map((n, i) => (
              <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '8px 12px', background: '#f8fafc', borderRadius: '8px' }}>
                <div>
                  <span style={{ fontFamily: 'monospace', fontWeight: 600, color: '#0f172a' }}>{n.phoneNumber}</span>
                  <span style={{ color: '#94a3b8', fontSize: '13px', marginLeft: '10px' }}>{n.friendlyName}</span>
                </div>
                <button
                  onClick={() => { setForm({ ...form, phone_number: n.phoneNumber, friendly_name: n.friendlyName }); setShowModal(true); }}
                  style={{ padding: '5px 12px', background: '#6366f1', border: 'none', borderRadius: '6px', color: 'white', fontSize: '12px', cursor: 'pointer', fontWeight: 500 }}>
                  Add
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Senders list */}
      {isLoading ? (
        <div style={{ textAlign: 'center', padding: '60px', color: '#94a3b8' }}>Loading...</div>
      ) : senders.length === 0 ? (
        <div style={{
          textAlign: 'center', padding: '60px', background: 'white',
          borderRadius: '16px', border: '2px dashed #e2e8f0',
        }}>
          <Phone size={40} style={{ color: '#cbd5e1', margin: '0 auto 16px' }} />
          <p style={{ color: '#94a3b8', fontWeight: 500 }}>No sender numbers yet</p>
          <p style={{ color: '#cbd5e1', fontSize: '13px', margin: '6px 0 20px' }}>
            Add your Twilio 10DLC-registered number to start sending campaigns
          </p>
          <button onClick={() => setShowModal(true)} style={{
            padding: '9px 20px', background: '#6366f1', border: 'none',
            borderRadius: '8px', color: 'white', fontWeight: 500, cursor: 'pointer',
          }}>Add First Number</button>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(360px, 1fr))', gap: '16px' }}>
          {senders.map(s => (
            <div key={s.id} style={{
              background: 'white', borderRadius: '14px',
              border: '1px solid #f1f5f9', padding: '20px',
              boxShadow: '0 1px 3px rgba(0,0,0,0.04)',
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '14px' }}>
                <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                  <div style={{
                    width: '42px', height: '42px', borderRadius: '10px',
                    background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                  }}>
                    <Phone size={18} color="white" />
                  </div>
                  <div>
                    <div style={{ fontFamily: 'monospace', fontWeight: 700, fontSize: '15px', color: '#0f172a' }}>
                      {s.phone_number}
                    </div>
                    {s.friendly_name && (
                      <div style={{ fontSize: '12px', color: '#64748b' }}>{s.friendly_name}</div>
                    )}
                  </div>
                </div>
                <StatusBadge status={s.status} />
              </div>

              {/* 10DLC info */}
              {(s.brand_name || s.brand_id_10dlc || s.campaign_id_10dlc) && (
                <div style={{ background: '#f8fafc', borderRadius: '8px', padding: '10px 12px', marginBottom: '14px' }}>
                  <div style={{ fontSize: '11px', fontWeight: 600, color: '#94a3b8', marginBottom: '6px' }}>10DLC DETAILS</div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                    {s.brand_name && (
                      <div style={{ fontSize: '13px', color: '#374151' }}>
                        <span style={{ color: '#94a3b8' }}>Brand: </span>{s.brand_name}
                      </div>
                    )}
                    {s.brand_id_10dlc && (
                      <div style={{ fontSize: '12px', color: '#374151', fontFamily: 'monospace' }}>
                        <span style={{ color: '#94a3b8', fontFamily: 'inherit' }}>Brand ID: </span>{s.brand_id_10dlc}
                      </div>
                    )}
                    {s.campaign_id_10dlc && (
                      <div style={{ fontSize: '12px', color: '#374151', fontFamily: 'monospace' }}>
                        <span style={{ color: '#94a3b8', fontFamily: 'inherit' }}>Campaign ID: </span>{s.campaign_id_10dlc}
                      </div>
                    )}
                  </div>
                </div>
              )}

              {/* Actions */}
              <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
                {isAdmin && s.status === 'pending' && (
                  <button
                    onClick={() => statusMutation.mutate({ id: s.id, status: 'approved' })}
                    style={{ padding: '6px 12px', background: '#dcfce7', border: 'none', borderRadius: '6px', color: '#16a34a', fontSize: '12px', fontWeight: 600, cursor: 'pointer' }}>
                    ✓ Approve
                  </button>
                )}
                {isAdmin && s.status === 'approved' && (
                  <button
                    onClick={() => statusMutation.mutate({ id: s.id, status: 'suspended' })}
                    style={{ padding: '6px 12px', background: '#fef3c7', border: 'none', borderRadius: '6px', color: '#d97706', fontSize: '12px', fontWeight: 600, cursor: 'pointer' }}>
                    Suspend
                  </button>
                )}
                {isAdmin && (
                  <button
                    onClick={() => { if (window.confirm('Remove this number?')) deleteMutation.mutate(s.id); }}
                    style={{ padding: '6px', background: '#fee2e2', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#dc2626' }}>
                    <Trash2 size={14} />
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ===== ADD NUMBER MODAL ===== */}
      {showModal && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px' }}>
          <div style={{ background: 'white', borderRadius: '20px', padding: '32px', width: '100%', maxWidth: '520px', maxHeight: '90vh', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '24px' }}>
              <h2 style={{ fontSize: '20px', fontWeight: 700, color: '#0f172a' }}>Add Sender Number</h2>
              <button onClick={() => { setShowModal(false); resetForm(); }} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}>
                <X size={20} />
              </button>
            </div>
            <form onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gap: '16px' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, marginBottom: '6px', color: '#374151' }}>Phone Number * <span style={{ color: '#94a3b8', fontWeight: 400 }}>(E.164 format)</span></label>
                  <input style={inp} placeholder="+12125551234" value={form.phone_number}
                    onChange={e => setForm({ ...form, phone_number: e.target.value })} required />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, marginBottom: '6px', color: '#374151' }}>Friendly Name</label>
                  <input style={inp} placeholder="e.g. Main Marketing Number" value={form.friendly_name}
                    onChange={e => setForm({ ...form, friendly_name: e.target.value })} />
                </div>

                {/* 10DLC section */}
                <div style={{ borderTop: '1px solid #f1f5f9', paddingTop: '16px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '14px' }}>
                    <ShieldCheck size={16} color="#6366f1" />
                    <span style={{ fontSize: '13px', fontWeight: 700, color: '#374151' }}>10DLC Information (Optional)</span>
                  </div>
                  <div style={{ display: 'grid', gap: '12px' }}>
                    <div>
                      <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, marginBottom: '6px', color: '#374151' }}>Brand Name</label>
                      <input style={inp} placeholder="Your registered brand name" value={form.brand_name}
                        onChange={e => setForm({ ...form, brand_name: e.target.value })} />
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                      <div>
                        <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, marginBottom: '6px', color: '#374151' }}>Brand ID</label>
                        <input style={inp} placeholder="BXXXXXXXX" value={form.brand_id_10dlc}
                          onChange={e => setForm({ ...form, brand_id_10dlc: e.target.value })} />
                      </div>
                      <div>
                        <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, marginBottom: '6px', color: '#374151' }}>Campaign ID</label>
                        <input style={inp} placeholder="CXXXXXXXX" value={form.campaign_id_10dlc}
                          onChange={e => setForm({ ...form, campaign_id_10dlc: e.target.value })} />
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <div style={{ display: 'flex', gap: '12px', marginTop: '24px', justifyContent: 'flex-end' }}>
                <button type="button" onClick={() => { setShowModal(false); resetForm(); }} style={{ padding: '10px 20px', border: '1px solid #e2e8f0', borderRadius: '8px', background: 'white', cursor: 'pointer', fontWeight: 500 }}>Cancel</button>
                <button type="submit" disabled={addMutation.isPending} style={{ padding: '10px 24px', background: 'linear-gradient(135deg, #6366f1, #8b5cf6)', border: 'none', borderRadius: '8px', color: 'white', fontWeight: 600, cursor: 'pointer' }}>
                  {addMutation.isPending ? 'Adding...' : 'Add Number'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* ===== 10DLC INFO MODAL ===== */}
      {showInfo && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px' }}>
          <div style={{ background: 'white', borderRadius: '20px', padding: '32px', width: '100%', maxWidth: '560px', maxHeight: '90vh', overflowY: 'auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h2 style={{ fontSize: '20px', fontWeight: 700, color: '#0f172a' }}>10DLC Registration Guide</h2>
              <button onClick={() => setShowInfo(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}>
                <X size={20} />
              </button>
            </div>
            {[
              { step: '1', title: 'Register Your Brand', desc: 'Go to Twilio Console → Messaging → 10DLC. Register your business as a brand. You\'ll need EIN (US), business name, address, and website.' },
              { step: '2', title: 'Create a Campaign Use Case', desc: 'After brand approval, create a campaign. Choose use case (Marketing, Notifications, etc.). Describe your messaging purpose clearly.' },
              { step: '3', title: 'Link Your Phone Number', desc: 'After campaign approval, link your Twilio number to the 10DLC campaign. This enables A2P SMS sending.' },
              { step: '4', title: 'Add Here', desc: 'Once approved, add your number here with the Brand ID and Campaign ID from Twilio Console.' },
            ].map(item => (
              <div key={item.step} style={{ display: 'flex', gap: '16px', marginBottom: '20px', paddingBottom: '20px', borderBottom: item.step !== '4' ? '1px solid #f1f5f9' : 'none' }}>
                <div style={{
                  width: '32px', height: '32px', borderRadius: '50%', flexShrink: 0,
                  background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  color: 'white', fontWeight: 700, fontSize: '14px',
                }}>{item.step}</div>
                <div>
                  <div style={{ fontWeight: 700, fontSize: '14px', color: '#0f172a', marginBottom: '4px' }}>{item.title}</div>
                  <div style={{ fontSize: '13px', color: '#64748b', lineHeight: 1.6 }}>{item.desc}</div>
                </div>
              </div>
            ))}
            <div style={{ background: '#fef3c7', borderRadius: '10px', padding: '14px', fontSize: '13px', color: '#92400e' }}>
              ⚠️ <strong>Sandbox numbers</strong> (like +14155238886) don't need 10DLC — they work immediately for testing. 10DLC is required only for production sending.
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
